// ─── ERRORES TURBOCHEF HHC2020/1618 ──────────────────────────────────────────
const ERRORES_TURBOCHEF = [
  {code:"F1 – Blower Failure",nivel:"CRÍTICO",desc:"Control no recibió señal OK del BMSC por 3 veces consecutivas. Termina la cocción. Causa: motor del blower trabado, BMSC dañado o cableado.",pasos:["Verificar energía en el circuito — revisar disyuntor de pared (40A para HHC2020, 30A para HHC1618).","Apagar y desconectar alimentación por 2 minutos. Reconectar y probar.","Acceder al end bell izquierdo y derecho. Verificar si hay código de falla en la pantalla del BMSC (CON-7013).","Verificar que el motor del blower gire libremente — si está trabado, buscar obstrucción o reemplazar motor (HCT-4205).","Medir resistencia de bobinas del motor: Negro-Rojo=2.3-2.8 ohms, Negro-Blanco=2.3-2.8 ohms, Rojo-Blanco=2.3-2.8 ohms. Bobina a chasis=abierto.","En TEST MODE (clave 2433): verificar indicadores de estado T y B en pantalla — deben aparecer TBTB cuando los motores están activos.","Si BMSC tiene código de falla → reemplazar BMSC CON-7013. Si motor no gira con voltaje correcto → reemplazar motor HCT-4205.","Si el cableado está bien y los componentes también → reemplazar tarjeta de control CON-7002."]},
  {code:"F2 – Low Temp During Cook",nivel:"MODERADO",desc:"Temperatura cayó 25°F/14°C bajo el set point durante cocción. No para el horno — solo registra en el contador de fallas.",pasos:["Verificar que la abertura de entrada/salida del conveyor no esté bloqueada.","Verificar que los plenums (placas de inyección de aire) estén correctamente instalados y sin obstrucciones.","En TEST MODE: probar elementos calefactores. Resistencia correcta de cada heater: 14.4 ohms a 208V, 6750 watts.","Verificar el RTD (HHC-6517-2): desconectar y poner en agua con hielo 2 minutos. Debe medir ~100 ohms. Si no → reemplazar RTD.","Si heaters y RTD están bien → verificar tarjeta de control CON-7002 y SSR (relay estado sólido NGC-3005)."]},
  {code:"F4 – Emergency Stop",nivel:"SIMPLE",desc:"Tecla de parada de emergencia fue presionada. Es solo un contador — no indica falla mecánica.",pasos:["Reiniciar el horno normalmente — el código se limpia solo.","Para ver cuántas veces se ha presionado: acceder CONFIG MODE y revisar fault counts.","Si aparece sin que nadie la presione → verificar el interruptor de emergencia y su cableado.","Limpiar fallas: TEST MODE (clave 2433) → pantalla 2 → ERASE/CLEAR → Clear Faults."]},
  {code:"F5 – CC Over Temp",nivel:"CRÍTICO",desc:"Temperatura de la cámara de cocción alcanzó o excedió 625°F/329°C. Termina la cocción.",pasos:["Apagar y dejar enfriar completamente.","Limpiar el horno a fondo — grasa acumulada en los heaters puede generar fuego y subir temperatura.","Verificar que los inyectores de aire (finger assemblies/jetplates HCT-4099) no estén obstruidos.","Verificar que el blower funcione correctamente — sin blower los heaters calientan sin control.","Verificar el high limit thermostat (102075, trip point 572°F/300°C) — si está disparado, resetear manualmente.","Si se repite frecuentemente → revisar solid state relay K4/K5 (NGC-3005) por posible cortocircuito."]},
  {code:"F6 – EC Over Temp",nivel:"CRÍTICO",desc:"Temperatura del compartimiento eléctrico alcanzó 158°F/70°C. Para la cocción cuando supera este límite.",pasos:["Verificar espacio libre mínimo: 254 mm (10 pulgadas) arriba y 51 mm (2 pulgadas) a cada lado.","Verificar que los filtros de aire traseros estén limpios — limpiar con compresor de aire (parte HCT-4067).","Verificar que los cooling fans funcionen (TC3-0433) — deben activarse cuando la temperatura en los end bells supera 120°F/49°C.","Verificar el termostato del cooling fan (102086) — medir continuidad: debe cerrar cuando hay calor.","NO instalar cerca de freidoras o fuentes de calor. Temperatura ambiente máxima: 120°F/49°C.","Verificar voltaje en el cooling fan: 208-240 VAC. Si llega voltaje y no gira → reemplazar fan TC3-0433."]},
  {code:"F7 – RTD Failure",nivel:"CRÍTICO",desc:"El RTD está abierto, en cortocircuito, o lee fuera de rango (-40°F a 645°F). Si muestra 999°F = RTD desconectado.",pasos:["Abrir el end bell derecho y verificar conexión del RTD (HHC-6517-2) a la tarjeta I/O.","Desconectar RTD y poner en agua con hielo 2 min. Medir resistencia: debe ser ~100 ohms a 32°F/0°C.","Tabla de resistencias RTD Clase B: 0°C=100ohm, 50°C=119ohm, 100°C=138ohm, 150°C=157ohm, 200°C=176ohm.","Si el RTD mide correcto → verificar cableado entre RTD y tarjeta. Si el cableado está bien → reemplazar tarjeta CON-7002.","Si RTD mide incorrecto → reemplazar RTD HHC-6517-2."]},
  {code:"F8 – High Limit Tripped",nivel:"CRÍTICO",desc:"El termostato de alto límite disparó (trip point 572°F/300°C). Causa más frecuente: grasa acumulada.",pasos:["Apagar y dejar enfriar completamente — el termostato se resetea manualmente.","Verificar si el high limit thermostat (102075) está disparado — buscar el botón de reset manual.","Limpiar el horno completamente: banda, plenums, jetplates, interior de la cámara.","Verificar que el indicador 'O' aparezca en la línea de estado del TEST MODE — si no aparece, el high limit está disparado.","Verificar el RTD (HHC-6517-2) y el solid state relay NGC-3005 — si el SSR tiene cortocircuito, los heaters calientan sin control.","PREVENTIVO: limpiar el horno diariamente — el 80% de los F8 se deben a falta de limpieza."]},
  {code:"F9 – Belt Fault",nivel:"MODERADO",desc:"El conveyor no arrancó o está arrastrando. La banda no gira a la velocidad correcta.",pasos:["Verificar que no haya objetos obstruyendo el movimiento de la banda.","Revisar la cadena del conveyor (HCT-4143, 52 eslabones): verificar que no esté suelta, dañada u obstruida con residuos.","Verificar tensión de cadena: la cadena debe estar tensa y debe pasar sin rozar el crumb tray holder.","Si la cadena está floja (demasiados eslabones desgastados) → retirar un eslabón o reemplazar cadena.","Abrir end bell. Verificar CMSC (HHC-6630-2): la pantalla del CMSC debe mostrar la frecuencia de salida durante operación normal.","Medir resistencia de las bobinas del motor conveyor: Blanco-Gris=305-315 ohms, Blanco-Negro=305-315 ohms, Gris-Negro=305-315 ohms.","Si motor, cadena y CMSC están bien → verificar cableado y tarjeta CON-7002."]},
  {code:"Pantalla en blanco / sin respuesta",nivel:"MODERADO",desc:"Display apagado o keypad sin respuesta.",pasos:["Verificar que los fusibles de 20A clase CC (100599) no estén quemados — ubicados en el fuse block izquierdo.","Verificar que la fuente de 24VDC (101211) tenga voltaje en sus terminales +V y -V (con cables desconectados).","Si la fuente tiene 24V sin carga pero no con carga → buscar cortocircuito en el cableado.","Medir 5VDC en pin 1 del conector J3 de la tarjeta de control — si no hay 5V, reemplazar tarjeta CON-7002.","Verificar el cable ribbon de display (100184) y el cable de poder del display (100193).","Si llega voltaje y pantalla no enciende → reemplazar display VFD NGC-3023."]},
  {code:"Alimento no se cocina correctamente",nivel:"COMÚN",desc:"Resultado de cocción inconsistente o incorrecto.",pasos:["Verificar que los plenums (HCT-4020) y jetplates (HCT-4099) estén correctamente instalados — si están al revés o fuera de posición, el flujo de aire cambia completamente.","Verificar temperatura y velocidad de banda en el perfil de cocción — acceder a edit mode (clave 6633 en Setup).","Verificar que el producto esté en el estado correcto (congelado, fresco) y en la cantidad correcta.","Verificar que los dos blower motors funcionen — en TEST MODE deben aparecer T1, T2, B1, B2 en los indicadores de estado.","Verificar los heaters: elemento trasero HCT-4161 y elemento frontal HCT-4162 — cada uno 14.4 ohms a 208V."]},
];

// ─── ERRORES ZANOLLI SYNTHESIS (Manual oficial Zanolli) ───────────────────────
const ERRORES_ZANOLLI = [
  {code:"OVER – Sobretemperatura",nivel:"CRÍTICO",desc:"Sonda 1 supera 350°C Y sonda 2 supera 450°C simultáneamente. La pantalla muestra 'OVER' parpadeando y suena la alarma.",pasos:["Presionar cualquier tecla para silenciar la alarma.","Apagar el horno inmediatamente con el interruptor ON/OFF.","NO continuar cocinando hasta que se enfríe completamente.","Verificar que la temperatura set no sea demasiado alta para el producto — el máximo recomendado del Synthesis es 350°C.","Verificar que la ventilación del local sea suficiente — temperatura ambiente máxima: 35°C.","Si ocurre a temperaturas normales de trabajo → contratar técnico certificado Zanolli para revisar sondas de temperatura y termostatos."]},
  {code:"BELT – Falla banda transportadora",nivel:"CRÍTICO",desc:"El motor de la banda envía señales incorrectas o no funciona. La pantalla muestra 'BELT' parpadeando. El tiempo de cocción no corresponde al valor programado.",pasos:["Silenciar alarma presionando cualquier tecla.","Apagar el horno y desconectar de corriente.","Inspeccionar la banda visualmente: buscar obstrucciones, residuos de queso o masa adheridos, o desgaste excesivo.","Verificar la tensión de la banda — debe estar firme y centrada en los rodillos.","Verificar el motor de la banda y su conector eléctrico.","Contratar técnico certificado Zanolli para diagnóstico del circuito de control de la banda."]},
  {code:"FAN – Falla presostato ventilador",nivel:"CRÍTICO",desc:"El presostato falla por 5 segundos consecutivos con el ventilador encendido. Pantalla 'FAN' parpadeando. El calentamiento se apaga automáticamente pero el ventilador y la banda siguen.",pasos:["Silenciar alarma.","Verificar que el presostato del ventilador esté correctamente conectado — revisar tuberías sin dobleces ni obstrucciones.","Calibrar el presostato: ajustar el tornillo de calibración en el centro del presostato hasta que se restablezca la señal.","Si las tuberías están bien y el presostato sigue fallando → reemplazar presostato.","Contratar técnico certificado Zanolli si el problema persiste."]},
  {code:"PRESS – Sin señal del presostato al arrancar",nivel:"CRÍTICO",desc:"No hay señal del presostato antes de encender el ventilador. La pantalla muestra 'PRESS' y el arranque se interrumpe.",pasos:["Verificar que las tuberías del presostato estén conectadas correctamente y sin dobleces.","Verificar que el presostato no esté obstruido — limpiar con soplado de aire.","Calibrar el presostato con el tornillo de ajuste.","Verificar que el ventilador no tenga obstrucciones físicas.","Desconectar y reconectar la alimentación para resetear la tarjeta base.","Si persiste → contratar técnico certificado Zanolli."]},
  {code:"FLAME – Falla detección de llama (solo gas)",nivel:"PELIGRO",desc:"El control de gas no detecta llama mientras el quemador está encendido o intentando encender. Solo hornos a gas.",pasos:["CERRAR LA LLAVE DE GAS INMEDIATAMENTE.","Ventilar el local por al menos 10 minutos.","NO intentar encender el horno.","Verificar que haya gas: abrir la llave principal y verificar presión — gas natural 20 mbar / LPG 30 mbar.","Verificar que los electrodos de ignición estén limpios y bien posicionados (distancia correcta al quemador).","Verificar el sensor de llama — limpiar con papel de lija fino si hay residuos de combustión.","Contratar técnico certificado en gas y equipos Zanolli para revisión completa del sistema de ignición."]},
  {code:"BATTERY – Batería de respaldo baja",nivel:"SIMPLE",desc:"La batería del buffer de la tarjeta electrónica base está agotada. La pantalla muestra 'BATTERY' con alarma intermitente.",pasos:["Esta alarma no impide el funcionamiento del horno.","Silenciar la alarma y programar el reemplazo de la batería.","La batería es una pila de botón ubicada en la tarjeta base principal.","Contratar técnico certificado para reemplazo — se debe desconectar la corriente para el cambio.","Después del reemplazo: desconectar y reconectar la alimentación para resetear la tarjeta base."]},
  {code:"Sonda defectuosa (probe 1 o probe 2)",nivel:"MODERADO",desc:"Una sonda de temperatura falla. El horno continúa funcionando solo con la sonda buena, pero eleva automáticamente 40°C el set point para compensar.",pasos:["El horno PUEDE seguir operando en modo de emergencia con una sola sonda.","La indicación de modo de emergencia aparece en pantalla.","Anotar cuál sonda está fallando (sonda 1 o sonda 2) para el reporte al técnico.","Programar la revisión con técnico certificado Zanolli para el reemplazo de la sonda.","NO usar el horno por largos periodos con una sola sonda — el control de temperatura es menos preciso."]},
  {code:"Llama inestable o se apaga (gas)",nivel:"FRECUENTE",desc:"El quemador de gas enciende pero la llama no es estable o se apaga durante la cocción.",pasos:["Verificar presión de gas: gas natural debe estar entre 17-25 mbar, LPG entre 25-37 mbar.","Verificar regulador de presión — si hay caida de presión excesiva durante operación → revisar regulador y línea.","Limpiar los quemadores — residuos carbonizados obstruyen los orificios de salida del gas.","Verificar sensor de llama — si está contaminado no detecta la llama correctamente. Limpiar con papel de lija muy fino.","Verificar gaps de electrodos de ignición — deben estar a la distancia correcta del quemador según el manual.","Si el ajuste de mínima potencia está muy bajo → ajustar la potencia mínima (ver procedimiento de ajuste en el manual técnico)."]},
  {code:"No alcanza temperatura programada",nivel:"COMÚN",desc:"El horno tarda demasiado o no llega a la temperatura set.",pasos:["Verificar presión de gas durante operación — la presión no debe caer más de 5 mbar con el quemador a máxima potencia.","Verificar que el ventilador de forzado de aire esté funcionando a la velocidad correcta.","Verificar que la cámara esté sellada — revisar empaque de la mirilla y sellos laterales.","Si la potencia del quemador a máxima intensidad no es suficiente → calibrar el regulador de gas. Contratar técnico certificado.","Verificar que la campana de extracción no tenga una succión excesiva que robe calor del horno."]},
];

